import { useState, useRef, useCallback, useEffect } from 'react'
import { Link, useLocation } from 'react-router-dom'
import { useGSAP } from '@gsap/react'
import gsap from 'gsap'

const NAV_LINKS = [
  { label: 'Projects', to: '/project' },
  { label: 'Studio',   to: '/studio' },
  { label: 'Journal',  to: '/journal' },
  { label: 'Contact',  to: '/contact' },
]

export default function Navbar() {
  const [menuOpen, setMenuOpen]   = useState(false)
  const [scrolled, setScrolled]   = useState(false)
  const menuRef      = useRef(null)
  const backdropRef  = useRef(null)
  const linksRef     = useRef([])
  const location     = useLocation()
  const isHome       = location.pathname === '/'

  /* ── lock body scroll when menu is open ── */
  useEffect(() => {
    document.body.style.overflow = menuOpen ? 'hidden' : ''
    return () => { document.body.style.overflow = '' }
  }, [menuOpen])

  /* ── close menu on route change ── */
  useEffect(() => { setMenuOpen(false) }, [location.pathname])

  /* ── listen to scroll for non-home nav glass effect ── */
  useEffect(() => {
    const onScroll = () => setScrolled(window.scrollY > 40)
    window.addEventListener('scroll', onScroll, { passive: true })
    return () => window.removeEventListener('scroll', onScroll)
  }, [])

  /* ── GSAP open/close ── */
  useGSAP(() => {
    if (!menuRef.current || !backdropRef.current) return

    if (menuOpen) {
      gsap.set(backdropRef.current, { visibility: 'visible' })
      gsap.to(backdropRef.current, { opacity: 1, duration: 0.5, ease: 'power2.out' })
      gsap.to(menuRef.current,     { x: 0,     duration: 1.2, ease: 'power4.inOut' })
      gsap.fromTo(
        linksRef.current.filter(Boolean),
        { x: 50, opacity: 0 },
        { x: 0, opacity: 1, duration: 0.7, stagger: 0.07, delay: 0.35, ease: 'power3.out' }
      )
    } else {
      gsap.to(backdropRef.current, {
        opacity: 0, duration: 0.55, ease: 'power2.inOut',
        onComplete: () => gsap.set(backdropRef.current, { visibility: 'hidden' }),
      })
      gsap.to(menuRef.current, { x: '100%', duration: 0.95, ease: 'power4.inOut' })
    }
  }, [menuOpen])

  const openMenu       = useCallback(() => setMenuOpen(true),  [])
  const closeMenu      = useCallback(() => setMenuOpen(false), [])

  /* ─────────────────────────────────────────────────────── */
  /*  SHARED – hamburger bars (used in both header variants) */
  /* ─────────────────────────────────────────────────────── */
  const HamburgerBars = ({ color = '#fff' }) => (
    <div style={{ display: 'flex', flexDirection: 'column', gap: '5px', zIndex: 2 }}>
      <span style={{ width: '22px', height: '1.5px', background: color, display: 'block', borderRadius: '2px', transition: 'background 0.4s' }} />
      <span style={{ width: '16px', height: '1.5px', background: color, display: 'block', borderRadius: '2px', transition: 'background 0.4s' }} />
    </div>
  )

  /* ─────────────────────────────────────────────────────── */
  /*  MENU TRIGGER BUTTON (circle on home / simple on inner) */
  /* ─────────────────────────────────────────────────────── */
  const MenuButton = ({ variant = 'circle' }) =>
    variant === 'circle' ? (
      <button
        onClick={openMenu}
        aria-label="Open navigation menu"
        aria-expanded={menuOpen}
        style={{
          width: '54px', height: '54px',
          borderRadius: '50%',
          border: '1px solid rgba(255,255,255,0.18)',
          background: 'rgba(255,255,255,0.06)',
          cursor: 'pointer',
          display: 'flex', alignItems: 'center', justifyContent: 'center',
          position: 'relative', overflow: 'hidden',
          transition: 'transform 0.7s var(--ease), border-color 0.4s',
          flexShrink: 0,
        }}
        onMouseEnter={e => { e.currentTarget.style.transform = 'rotate(90deg) scale(1.06)' }}
        onMouseLeave={e => { e.currentTarget.style.transform = 'rotate(0deg) scale(1)' }}
      >
        <HamburgerBars />
      </button>
    ) : (
      <button
        onClick={openMenu}
        aria-label="Open navigation menu"
        aria-expanded={menuOpen}
        style={{
          background: 'none', border: 'none', cursor: 'pointer',
          padding: '8px', display: 'flex', flexDirection: 'column',
          gap: '5px', alignItems: 'flex-end',
        }}
      >
        <HamburgerBars color="#fff" />
      </button>
    )

  /* ─────────────────────────────────────────────────────── */
  return (
    <>
      {/* ══════════════════ BACKDROP ══════════════════════ */}
      <div
        ref={backdropRef}
        onClick={closeMenu}
        style={{
          position: 'fixed', inset: 0,
          background: 'rgba(0,0,0,0.5)',
          backdropFilter: 'blur(8px)',
          WebkitBackdropFilter: 'blur(8px)',
          zIndex: 8000,
          opacity: 0, visibility: 'hidden',
        }}
      />

      {/* ══════════════════ SLIDE MENU ════════════════════ */}
      <nav
        ref={menuRef}
        role="dialog"
        aria-modal="true"
        aria-label="Site navigation"
        style={{
          position: 'fixed',
          top: 0, right: 0,
          width: 'min(520px, 100vw)',
          height: '100dvh',       /* dvh respects mobile browser chrome */
          background: '#f7f4ef',
          zIndex: 9000,
          padding: 'clamp(100px,12vh,140px) clamp(32px,7vw,70px) 60px',
          transform: 'translateX(100%)',
          overflowY: 'auto',
          overflowX: 'hidden',
          display: 'flex',
          flexDirection: 'column',
        }}
      >
        {/* grid texture overlay */}
        <div
          aria-hidden="true"
          style={{
            position: 'absolute', inset: 0, opacity: 0.4, pointerEvents: 'none',
            backgroundImage:
              'linear-gradient(rgba(0,0,0,.03) 1px,transparent 1px),' +
              'linear-gradient(90deg,rgba(0,0,0,.03) 1px,transparent 1px)',
            backgroundSize: '42px 42px',
          }}
        />
        {/* radial glow corner */}
        <div
          aria-hidden="true"
          style={{
            position: 'absolute', top: '-120px', right: '-120px',
            width: '420px', height: '420px', borderRadius: '50%',
            background: 'radial-gradient(circle,rgba(0,0,0,.05),transparent 70%)',
            filter: 'blur(30px)', pointerEvents: 'none',
          }}
        />
        {/* decorative corner bracket */}
        <div
          aria-hidden="true"
          style={{
            position: 'absolute',
            left: 'clamp(32px,7vw,60px)', top: '36px',
            width: '90px', height: '90px',
            borderTop: '1px solid rgba(0,0,0,0.10)',
            borderLeft: '1px solid rgba(0,0,0,0.10)',
            opacity: 0.7, pointerEvents: 'none',
          }}
        />

        {/* ─── Close button ─── */}
        <button
          onClick={closeMenu}
          aria-label="Close menu"
          style={{
            position: 'absolute', top: '30px', right: 'clamp(20px,5vw,42px)',
            width: '48px', height: '48px',
            border: 'none', background: '#111', color: '#fff',
            borderRadius: '50%', cursor: 'pointer',
            fontSize: '22px', fontWeight: 300,
            display: 'flex', alignItems: 'center', justifyContent: 'center',
            zIndex: 2, transition: 'transform 0.65s var(--ease)',
            lineHeight: 1,
          }}
          onMouseEnter={e => { e.currentTarget.style.transform = 'rotate(180deg) scale(1.08)' }}
          onMouseLeave={e => { e.currentTarget.style.transform = 'rotate(0deg) scale(1)' }}
        >
          ×
        </button>

        {/* ─── Navigation links ─── */}
        <ul
          style={{
            position: 'relative', zIndex: 2,
            listStyle: 'none', padding: 0, margin: 0,
            display: 'flex', flexDirection: 'column',
            gap: 'clamp(20px,3.5vh,32px)',
            flex: 1,
          }}
        >
          {NAV_LINKS.map((link, i) => {
            const isActive = location.pathname === link.to
            return (
              <li key={link.label} style={{ overflow: 'hidden' }}>
                <Link
                  ref={el => (linksRef.current[i] = el)}
                  to={link.to}
                  onClick={closeMenu}
                  style={{
                    position: 'relative',
                    color: isActive ? '#836e62' : '#111',
                    textDecoration: 'none',
                    fontFamily: 'var(--serif)',
                    fontSize: 'clamp(36px, 7vw, 52px)',
                    textTransform: 'uppercase',
                    letterSpacing: '2px',
                    display: 'inline-block',
                    lineHeight: 1.1,
                    transition: 'transform 0.9s var(--ease), letter-spacing 0.9s var(--ease), color 0.3s',
                  }}
                  onMouseEnter={e => {
                    e.currentTarget.style.transform = 'translateX(22px)'
                    e.currentTarget.style.letterSpacing = '6px'
                  }}
                  onMouseLeave={e => {
                    e.currentTarget.style.transform = 'translateX(0)'
                    e.currentTarget.style.letterSpacing = '2px'
                  }}
                >
                  {link.label}
                </Link>
              </li>
            )
          })}
        </ul>

        {/* ─── Menu footer info ─── */}
        <div
          style={{
            position: 'relative', zIndex: 2,
            marginTop: 'clamp(40px, 6vh, 60px)',
            fontSize: '11px', letterSpacing: '3.5px',
            textTransform: 'uppercase', color: '#888',
            lineHeight: 2,
          }}
        >
          studio@rakeshsharmadesign.com<br />
          Indore — India
        </div>
      </nav>

      {/* ══════════════════════════════════════════════════
          HOME PAGE — floating glass pill header
      ════════════════════════════════════════════════════ */}
      {isHome && (
        <header
          style={{
            position: 'fixed',
            top: '16px',
            left: '50%',
            transform: 'translateX(-50%)',
            width: 'min(94%, 1600px)',
            height: 'clamp(68px, 9vh, 92px)',
            zIndex: 5000,
            display: 'grid',
            gridTemplateColumns: 'auto 1fr auto',
            alignItems: 'center',
            padding: '0 clamp(16px, 3vw, 36px)',
            borderRadius: '30px',
            background: 'rgba(0,0,0,0.40)',
            backdropFilter: 'blur(20px)',
            WebkitBackdropFilter: 'blur(20px)',
            border: '1px solid rgba(255,255,255,0.09)',
            overflow: 'hidden',
          }}
        >
          {/* shimmer sweep */}
          <div
            aria-hidden="true"
            style={{
              position: 'absolute', top: 0, left: '-300px',
              width: '300px', height: '100%',
              background: 'linear-gradient(90deg,transparent,rgba(255,255,255,0.06),transparent)',
              animation: 'glassMove 8s linear infinite',
              pointerEvents: 'none',
            }}
          />

          {/* LEFT — RSD monogram */}
          <Link to="/" style={{ textDecoration: 'none', display: 'flex', alignItems: 'center' }}>
            <div
              style={{
                display: 'flex', alignItems: 'center',
                fontFamily: 'var(--sans)', fontWeight: 800,
                textTransform: 'uppercase', letterSpacing: '-2px',
                lineHeight: 1,
              }}
            >
              {['R', 'S', 'D'].map((l, i) => (
                <span
                  key={l}
                  style={{
                    fontSize: 'clamp(32px, 5.5vw, 62px)',
                    background: 'linear-gradient(to bottom,#fff,#d8d8d8)',
                    WebkitBackgroundClip: 'text',
                    WebkitTextFillColor: 'transparent',
                    backgroundClip: 'text',
                    marginLeft: i > 0 ? 'clamp(-6px,-1vw,-10px)' : undefined,
                    display: 'block',
                  }}
                >
                  {l}
                </span>
              ))}
            </div>
          </Link>

          {/* CENTER — brand name (hidden on very small screens) */}
          <div style={{ textAlign: 'center' }}>
            <Link
              to="/"
              style={{
                color: '#fff',
                textDecoration: 'none',
                fontFamily: 'var(--serif)',
                fontSize: 'clamp(13px, 2.2vw, 28px)',
                letterSpacing: 'clamp(3px, 1vw, 10px)',
                textTransform: 'uppercase',
                whiteSpace: 'nowrap',
                display: 'block',
                overflow: 'hidden',
                textOverflow: 'ellipsis',
              }}
            >
              <span className="nav-brand-full">Rakesh Sharma Design</span>
              <span className="nav-brand-short">RSD</span>
            </Link>
          </div>

          {/* RIGHT — trigger */}
          <div style={{ display: 'flex', justifyContent: 'flex-end' }}>
            <MenuButton variant="circle" />
          </div>
        </header>
      )}

      {/* ══════════════════════════════════════════════════
          INNER PAGES — solid dark top bar
      ════════════════════════════════════════════════════ */}
      {!isHome && (
        <header
          style={{
            position: 'fixed',
            top: 0, left: 0,
            width: '100%',
            height: 'clamp(60px, 8vh, 80px)',
            zIndex: 5000,
            display: 'flex',
            justifyContent: 'space-between',
            alignItems: 'center',
            padding: '0 clamp(20px, 5vw, 60px)',
            background: scrolled
              ? 'rgba(10,31,22,0.97)'
              : 'rgba(10,31,22,0.92)',
            backdropFilter: 'blur(16px)',
            WebkitBackdropFilter: 'blur(16px)',
            borderBottom: '1px solid rgba(255,255,255,0.07)',
            transition: 'background 0.4s ease, box-shadow 0.4s ease',
            boxShadow: scrolled ? '0 4px 30px rgba(0,0,0,0.3)' : 'none',
          }}
        >
          {/* Brand logo */}
          <Link
            to="/"
            style={{
              fontSize: 'clamp(11px, 1.6vw, 14px)',
              textTransform: 'uppercase',
              letterSpacing: 'clamp(2px, 0.4vw, 5.6px)',
              fontWeight: 700,
              color: '#fff',
              textDecoration: 'none',
              fontFamily: 'var(--sans)',
              whiteSpace: 'nowrap',
              transition: 'opacity 0.3s',
            }}
            onMouseEnter={e => { e.currentTarget.style.opacity = '0.75' }}
            onMouseLeave={e => { e.currentTarget.style.opacity = '1' }}
          >
            <span className="nav-brand-full">Rakesh Sharma Designs</span>
            <span className="nav-brand-short">RSD</span>
          </Link>

          {/* Current page breadcrumb (tablet+) */}
          <span
            className="nav-page-label"
            style={{
              fontSize: '10px',
              textTransform: 'uppercase',
              letterSpacing: '3px',
              color: 'rgba(255,255,255,0.45)',
              fontFamily: 'var(--sans)',
            }}
          >
            {NAV_LINKS.find(n => n.to === location.pathname)?.label ?? ''}
          </span>

          {/* Trigger */}
          <MenuButton variant="simple" />
        </header>
      )}

      {/* ══════════════════════════════════════════════════
          RESPONSIVE STYLE RULES (injected once)
      ════════════════════════════════════════════════════ */}
      <style>{`
        /* Brand name display logic */
        .nav-brand-full  { display: inline; }
        .nav-brand-short { display: none; }

        @media (max-width: 480px) {
          .nav-brand-full  { display: none; }
          .nav-brand-short { display: inline; }
          .nav-page-label  { display: none; }
        }

        @media (max-width: 360px) {
          .nav-brand-short { font-size: 11px; letter-spacing: 2px; }
        }

        /* Glassmove shimmer on home pill */
        @keyframes glassMove {
          0%   { left: -300px; }
          100% { left: 130%; }
        }

        /* Ensure slide menu never clips on landscape mobile */
        @media (max-height: 500px) {
          nav[role="dialog"] {
            padding-top: 80px !important;
          }
          nav[role="dialog"] ul li a {
            font-size: clamp(28px, 6vw, 40px) !important;
          }
        }

        /* Tap target safety on touch */
        @media (hover: none) {
          nav[role="dialog"] ul li a:hover {
            transform: none !important;
            letter-spacing: 2px !important;
          }
        }
      `}</style>
    </>
  )
}
